    const childNode = new Node(childDb, childPath, 'working');
    this._ancestors = [frozen, ...this._ancestors];
    this._working = childNode;
    this._owned.add(childNode);
    return {
      id: frozen.id,
      label: frozen.label,
      path: frozen.path,
      depth: this._ancestors.length,
    };
  }

  /**
   * Discard all edits since a checkpoint and resume from it. With no argument,
   * rolls back to the most recent checkpoint. Abandons the poisoned working
   * child and derives a fresh writable child off the chosen checkpoint.
   * @param {string} [checkpointId] fileId of the checkpoint to return to
   * @returns {{restoredTo:string, depth:number}}
   */
  rollback(checkpointId) {
    this._assertOpen();
    if (this._ancestors.length === 0) {
      throw new Error('agenticow: nothing to roll back to (no checkpoints)');
    }
    let idx = 0; // default: most recent checkpoint
    if (checkpointId) {
      idx = this._ancestors.findIndex((n) => n.id === checkpointId);
      if (idx === -1) throw new Error(`agenticow: checkpoint ${checkpointId} not found`);
    }
    // Discard the current poisoned working child and any checkpoints newer than
    // target — but only ones THIS instance owns (never a shared ancestor).
    const discarded = [this._working, ...this._ancestors.slice(0, idx)];
    for (const n of discarded) {
      if (!this._owned.has(n)) continue;
      try { n.db.close(); } catch { /* ignore */ }
      try { fs.rmSync(n.path, { force: true }); } catch { /* ignore */ }
      this._owned.delete(n);
    }
    const target = this._ancestors[idx];
    const newAncestors = this._ancestors.slice(idx); // target + older
    const childPath = tmpChildPath(target.path, 'work');
    const childDb = target.db.derive(childPath, this._deriveOpts());
    this._working = new Node(childDb, childPath, 'working');
    this._owned.add(this._working);
    this._ancestors = newAncestors;
    return { restoredTo: target.id, depth: this._ancestors.length };
  }

  /** Lineage chain metadata, working node first. */
  lineage() {
    const chain = this._chain();
    return chain.map((n, i) => ({
      role: i === 0 ? 'working' : (i === chain.length - 1 ? 'base' : 'checkpoint'),
      id: n.id,
      label: n.label,
      path: n.path,
      parent: i < chain.length - 1 ? chain[i + 1].id : null,
      createdAt: n.createdAt,
      mutations: n.editIds.size,
      tombstones: n.tombstones.size,
    }));
  }

  /** Status of the working node plus chain depth. */
  status() {
    this._assertOpen();
    const s = this._working.db.status();
    return {
      ...s,
      chainDepth: this._chain().length,
      dimension: this._dim,
      metric: this._metric,
    };
  }

  /** dimension of stored vectors */
  get dimension() {
    return this._dim;
  }

  /**
   * Persist the lineage to a small JSON manifest so the CLI (or another process)
   * can reopen the exact chain. Vector data stays in the .rvf files; the manifest
   * holds the chain order, labels, tombstones and (for diff/promote) the working
   * node's recorded edits.
   * @param {string} manifestPath
   */
  save(manifestPath) {
    this._assertOpen();
    const nodes = this._chain().map((n, i) => ({
      path: path.resolve(n.path),
      label: n.label,
      tombstones: [...n.tombstones],
      // only the working node (i===0) needs its edit vectors for promote()
      editIds: i === 0 ? [...n.editIds] : [],
      editVecs: i === 0 ? Object.fromEntries([...n.editVecs].map(([id, v]) => [id, Array.from(v)])) : {},
    }));
    fs.writeFileSync(manifestPath, JSON.stringify({ v: 1, dim: this._dim, metric: this._metric, track: this._track, nodes }, null, 2));
    return manifestPath;
  }

     // only the working node (i===0) needs its edit vectors for promote()
      editIds: i === 0 ? [...n.editIds] : [],
      editVecs: i === 0 ? Object.fromEntries([...n.editVecs].map(([id, v]) => [id, Array.from(v)])) : {},
    }));
    fs.writeFileSync(manifestPath, JSON.stringify({ v: 1, dim: this._dim, metric: this._metric, track: this._track, nodes }, null, 2));
    return manifestPath;
  }

  /**
   * Reconstruct an AgenticMemory from a manifest written by save().
   * @param {string} manifestPath
   * @returns {AgenticMemory}
   */
  static load(manifestPath) {
    const m = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));
    const nodes = m.nodes.map((nm, i) => {
      const db = i === 0 ? RvfDatabase.open(nm.path) : RvfDatabase.openReadonly(nm.path);
      const node = new Node(db, nm.path, nm.label);
      node.tombstones = new Set(nm.tombstones || []);
      node.editIds = new Set(nm.editIds || []);
      node.editVecs = new Map(Object.entries(nm.editVecs || {}).map(([id, v]) => [Number(id), Float32Array.from(v)]));
      return node;
    });
    // A loaded instance opened every handle itself, so it owns the whole chain.
    return new AgenticMemory(nodes[0], nodes.slice(1), m.dim, m.metric, m.track !== false, new Set(nodes));
  }

  /** Close the handles this instance owns (never a shared parent/base handle). */
  close() {
    if (this._closed) return;
    for (const n of this._owned) {
      try { n.db.close(); } catch { /* ignore */ }
    }
    this._closed = true;
  }
}

/** Convenience: open or create a memory. @see AgenticMemory.open */
export function open(filePath, opts) {
  return AgenticMemory.open(filePath, opts);
}

/**
 * Alias of {@link open}. Provided so documented snippets that read
 * `import { openBase } from 'agenticow'` run verbatim. Identical behavior.
 */
export const openBase = open;

export default { open, openBase, AgenticMemory };

// Type declarations for agenticow — Git for Agent Memory.

export interface OpenOptions {
  /** Vector dimension. Required when creating a new memory file. */
  dimension?: number;
  /** Distance metric. Default: "cosine". */
  metric?: string;
  /** HNSW M parameter (optional, create only). */
  m?: number;
  /** HNSW efConstruction (optional, create only). */
  efConstruction?: number;
  /** Keep an in-memory edit log enabling diff()/promote(). Default: true. */
  track?: boolean;
}

export interface MemoryDiff {
  added: number[];
  overridden: number[];
  deleted: number[];
}

export interface IngestResult {
  accepted: number;
  rejected: number;
  epoch: number;
}

export interface QueryOptions {
  /** HNSW efSearch passed to each store in the lineage chain. */
  efSearch?: number;
  /** Candidates to over-fetch per store before exact merge. Default: k*4. */
  overscan?: number;
  /**
   * Force the exact JS chain-walk even on a native-COW fork.
   * Default false (native path used when available).
   */
  forceExact?: boolean;
}

export interface ForkOptions {
  /**
   * Use the native Rust COW dual-graph ANN path (PR #618).
   * When true, fork() calls RvfDatabase.branch() instead of derive(), giving
   * the returned fork a working node whose query() spans the COW boundary in
   * a single Rust call. recall@10 = 1.0 at 1200-vector L2 test corpus.
   * Default: false (exact JS chain-walk).
   */
  nativeAnn?: boolean;
}

export interface QueryHit {
  id: number;
  distance: number;
  /** label/id of the lineage node the hit came from (which "wins"). */
  branch: string;
  /** optional text/payload set via ingest(vec,{text}) / ingest([{id,vector,text}]). */
  text?: string;
}

export interface IngestPayload {
  /** explicit id; auto-assigned when omitted. */
  id?: number;
  /** optional text/payload stored for this id, surfaced on query hits. */
  text?: string;
}

export interface QueryOptionsTopK extends QueryOptions {
  /** number of nearest neighbors to return (alias of the positional `k`). */
  topK?: number;
  k?: number;
}

export interface CheckpointDescriptor {
  id: string;
  label: string;
  path: string;
  depth: number;
}

export interface LineageNode {
  role: 'working' | 'checkpoint' | 'base';
  id: string;
  label: string | null;
  path: string;
  /** fileId of the parent node (null for the base). */
  parent: string | null;
  /** epoch ms when this node was created. */
  createdAt: number;
  /** number of ids ingested at this node (requires track). */
  mutations: number;
  tombstones: number;
}

export interface MemoryStatus {
  totalVectors: number;
  totalSegments: number;
  fileSize: number;
  currentEpoch: number;
  profileId: number;
  compactionState: string;
  deadSpaceRatio: number;
  readOnly: boolean;
  chainDepth: number;
  dimension: number;
  metric: string;
}

export type IngestRecord = { id: number; vector: number[] | Float32Array; text?: string };

export class AgenticMemory {
  static open(filePath: string, opts?: OpenOptions): AgenticMemory;
  readonly dimension: number;
  /**
   * True when this fork was created with `{nativeAnn:true}`.
   * query() routes through the Rust dual-graph ANN merge (PR #618).
   */
  readonly nativeAnn: boolean;
  ingest(records: IngestRecord[]): IngestResult;
  ingest(vectors: Float32Array, ids: number[]): IngestResult;
  /** Convenience single-vector form: ingest(vec, { text?, id? }). Auto-ids when omitted. */
  ingest(vector: number[] | Float32Array, payload?: IngestPayload): IngestResult;
  delete(ids: number[]): { deleted: number; tombstoned: number };
  query(vector: number[] | Float32Array, k?: number, opts?: QueryOptions): QueryHit[];
  /** Convenience options form: query(vec, { topK, efSearch?, overscan? }). */
  query(vector: number[] | Float32Array, opts: QueryOptionsTopK): QueryHit[];
  branch(label?: string, filePath?: string): AgenticMemory;
  fork(label?: string, filePath?: string, opts?: ForkOptions): AgenticMemory;
  diff(): MemoryDiff;
  /** Promote this branch's edits into `target`; defaults to the fork/branch parent when omitted. */
  promote(target?: AgenticMemory): { ingested: number; deleted: number };
  checkpoint(label?: string): CheckpointDescriptor;
  rollback(checkpointId?: string): { restoredTo: string; depth: number };
  lineage(): LineageNode[];
  status(): MemoryStatus;
  save(manifestPath: string): string;
  static load(manifestPath: string): AgenticMemory;
  close(): void;
}

export function open(filePath: string, opts?: OpenOptions): AgenticMemory;
/** Alias of {@link open}; lets `import { openBase }` snippets run verbatim. */
export function openBase(filePath: string, opts?: OpenOptions): AgenticMemory;

declare const _default: {
  open: typeof open;
  openBase: typeof openBase;
  AgenticMemory: typeof AgenticMemory;
};
export default _default;

#!/usr/bin/env node
// agenticow CLI — Git for Agent Memory.
//
// Stateful verbs operate on a memory file (e.g. memory.rvf) plus a sibling
// lineage manifest (memory.rvf.agenticow.json) that tracks the COW chain.
//
//   agenticow init   <file> --dim <n>           create a base memory
//   agenticow ingest <file> --n <n>             ingest n random vectors (demo data)
//   agenticow branch <file> --as <label>        COW-fork the memory (per-user/per-repo)
//   agenticow checkpoint <file> --as <label>    freeze a restore point
//   agenticow rollback  <file>                  discard edits since last checkpoint
//   agenticow diff   <file>                     show added / overridden / tombstoned ids
//   agenticow promote <branchFile> <intoFile>   merge a branch's edits into a base
//   agenticow query  <file> --k <k>             top-K read-through (tombstone-masked, reranked)
//   agenticow lineage <file>                    show the COW chain
//
//   agenticow demo          scripted end-to-end walkthrough
//   agenticow bench         COW branch-create benchmark (SIZES env to add 1M)
//   agenticow acceptance    1,000-branch acceptance proof (BASE/BRANCHES env)
//   agenticow help          this help

import { fileURLToPath } from 'node:url';
import path from 'node:path';
import fs from 'node:fs';
import os from 'node:os';
import { spawnSync } from 'node:child_process';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const LIB = path.join(ROOT, 'src', 'index.js');

const C = { r: '\x1b[0m', b: '\x1b[1m', d: '\x1b[2m', c: '\x1b[36m', g: '\x1b[32m', y: '\x1b[33m', m: '\x1b[35m', red: '\x1b[31m' };
const col = (k, s) => `${C[k]}${s}${C.r}`;

function manifestFor(file) { return `${file}.agenticow.json`; }
function rndVec(dim) { return Float32Array.from({ length: dim }, () => Math.random() * 2 - 1); }

function parseArgs(argv) {
  const pos = [];
  const flags = {};
  for (let i = 0; i < argv.length; i++) {
    if (argv[i].startsWith('--')) { flags[argv[i].slice(2)] = argv[i + 1] && !argv[i + 1].startsWith('--') ? argv[++i] : true; }
    else pos.push(argv[i]);
  }
  return { pos, flags };
}

function help() {
  console.log(`
${col('b', 'agenticow')} — ${col('c', 'Git for Agent Memory')}
Copy-on-write vector branching: branch a base memory in ~0.5 ms / 162 bytes,
regardless of base size. Exact read-through (parent ∪ edits, child wins).

${col('b', 'Stateful verbs')} (operate on <file> + its lineage manifest)
  init       <file> --dim <n>            create a base memory
  ingest     <file> --n <n>              ingest n random demo vectors
  branch     <file> --as <label>         COW-fork (per-user / per-repo personalization)
  checkpoint <file> --as <label>         freeze a restore point
  rollback   <file>                      discard edits since last checkpoint
  diff       <file>                      added / overridden / tombstoned ids
  promote    <branchFile> <intoFile>     merge a branch's edits into a base
  query      <file> --k <k>              top-K read-through (tombstone-masked, reranked)
  lineage    <file>                      show the COW chain

${col('b', 'Showcases')}
  demo                                   scripted end-to-end walkthrough
  bench                                  branch-create benchmark
  acceptance                             1,000-branch acceptance proof
  help                                   this help

${col('b', 'Example')}
  agenticow init mem.rvf --dim 128
  agenticow ingest mem.rvf --n 5000
  agenticow branch mem.rvf --as user-42      ${col('d', '# cheap personalization')}
  agenticow query  mem.rvf.user-42.rvf --k 10
`);
}

function runChild(script, env) {
  const res = spawnSync(process.execPath, [path.join(ROOT, 'bench', script)], { stdio: 'inherit', env: { ...process.env, ...env } });
  process.exit(res.status || 0);
}

async function lib() { return import(LIB); }

async function cmdInit(pos, flags) {
  const { open } = await lib();
  const file = pos[0];
  const dim = Number(flags.dim || 128);
  if (!file) throw new Error('usage: agenticow init <file> --dim <n>');
  const mem = open(file, { dimension: dim, metric: flags.metric || 'cosine' });
  mem.save(manifestFor(file));
  mem.close();
  console.log(`${col('g', '✓')} created base memory ${col('c', file)} (dim ${dim})`);
}

async function loadMem(file) {
  const { AgenticMemory, open } = await lib();
  const man = manifestFor(file);
  if (fs.existsSync(man)) return { mem: AgenticMemory.load(man), man };
  if (fs.existsSync(file)) { const mem = open(file); return { mem, man }; }
  throw new Error(`no such memory: ${file} (run: agenticow init ${file} --dim <n>)`);
}

async function cmdIngest(pos, flags) {
  const file = pos[0];
  const n = Number(flags.n || 100);
  const { mem, man } = await loadMem(file);
  const dim = mem.dimension;
  const flat = new Float32Array(n * dim);
  const ids = [];
  const base = Number(flags.startId || Math.floor(Math.random() * 1e6));
  for (let i = 0; i < n; i++) { flat.set(rndVec(dim), i * dim); ids.push(base + i); }
  const res = mem.ingest(flat, ids);
  mem.save(man);
  mem.close();
  console.log(`${col('g', '✓')} ingested ${col('g', res.accepted)} vectors into ${col('c', file)} (ids ${base}..${base + n - 1})`);
}

async function cmdBranch(pos, flags) {
  const file = pos[0];
  const label = flags.as || 'branch';
  const { mem, man } = await loadMem(file);
  const childPath = flags.out || path.join(path.dirname(file), `${path.basename(file).replace(/\.rvf$/, '')}.${label}.rvf`);
  const t0 = performance.now();
  const br = mem.fork(label, childPath);
  const ms = performance.now() - t0;
  const bytes = fs.statSync(childPath).size;
  br.save(manifestFor(childPath));
  mem.save(man); // base unchanged by fork, but keep manifest fresh
  br.close(); mem.close();
  console.log(`${col('g', '✓')} branched ${col('c', file)} -> ${col('m', childPath)}`);
  console.log(`  ${col('g', ms.toFixed(3) + ' ms')} / ${col('g', bytes + ' B')} (O(1) in base size)`);
}

async function cmdCheckpoint(pos, flags) {
  const file = pos[0];
  const { mem, man } = await loadMem(file);
  const ck = mem.checkpoint(flags.as || undefined);
  mem.save(man);
  mem.close();
  console.log(`${col('g', '✓')} checkpoint ${col('m', ck.label)} (id ${ck.id.slice(0, 12)}…, depth ${ck.depth}, 162 B)`);
}

async function cmdRollback(pos, flags) {
  const file = pos[0];
  const { mem, man } = await loadMem(file);
  const t0 = performance.now();
  const r = mem.rollback(flags.to || undefined);
  const ms = performance.now() - t0;
  mem.save(man);
  mem.close();
  console.log(`${col('g', '✓')} rolled back to ${col('m', r.restoredTo.slice(0, 12) + '…')} in ${col('g', ms.toFixed(3) + ' ms')} (depth ${r.depth})`);
}

async function cmdDiff(pos) {
  const file = pos[0];
  const { mem } = await loadMem(file);
  const d = mem.diff();
  mem.close();
  console.log(`${col('b', 'diff')} ${col('c', file)} vs parent`);
  console.log(`  ${col('g', '+ added     ')} ${d.added.length} ids ${d.added.length ? col('d', '[' + d.added.slice(0, 8).join(', ') + (d.added.length > 8 ? ', …' : '') + ']') : ''}`);
  console.log(`  ${col('y', '~ overridden')} ${d.overridden.length} ids ${d.overridden.length ? col('d', '[' + d.overridden.slice(0, 8).join(', ') + (d.overridden.length > 8 ? ', …' : '') + ']') : ''}`);
  console.log(`  ${col('red', '- deleted   ')} ${d.deleted.length} ids ${d.deleted.length ? col('d', '[' + d.deleted.slice(0, 8).join(', ') + (d.deleted.length > 8 ? ', …' : '') + ']') : ''}`);
}

async function cmdPromote(pos) {
  const [branchFile, intoFile] = pos;
  if (!branchFile || !intoFile) throw new Error('usage: agenticow promote <branchFile> <intoFile>');
  const br = await loadMem(branchFile);
  const target = await loadMem(intoFile);
  const r = br.mem.promote(target.mem);
  target.mem.save(target.man);
  br.mem.close(); target.mem.close();
  console.log(`${col('g', '✓')} promoted ${col('m', branchFile)} -> ${col('c', intoFile)}: ` +
    `${col('g', r.ingested)} vectors merged, ${col('red', r.deleted)} tombstoned`);
}

async function cmdQuery(pos, flags) {
  const file = pos[0];
  const k = Number(flags.k || 10);
  const { mem } = await loadMem(file);
  // random probe (CLI is for demonstrating the read-through path)
  const q = rndVec(mem.dimension);
  const hits = mem.query(q, k);
  mem.close();
  console.log(`${col('b', `top-${k} read-through`)} for ${col('c', file)} (tombstone-masked, reranked)`);
  for (const h of hits) {
    console.log(`  id ${col('g', String(h.id).padStart(10))}  dist ${col('y', h.distance.toFixed(4))}  ${col('d', 'from ' + h.branch)}`);
  }
}

async function cmdLineage(pos) {
  const file = pos[0];
  const { mem } = await loadMem(file);
  const chain = mem.lineage();
  mem.close();
  console.log(`${col('b', 'lineage')} ${col('c', file)} (working → base)`);
  chain.forEach((n, i) => {
    const arm = i === chain.length - 1 ? '└─' : '├─';
    console.log(`  ${arm} ${col('m', n.role.padEnd(10))} ${col('d', n.id.slice(0, 12) + '…')}  ${n.label || ''}  ${n.tombstones ? col('red', n.tombstones + ' tombstones') : ''}`);
  });
}

async function demo() {
  const { open } = await lib();
  const DIM = 32;
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'agenticow-demo-'));
  const rnd = () => rndVec(DIM);
  const line = () => console.log(col('d', '─'.repeat(64)));
  console.log(`\n${col('b', 'agenticow demo')} — ${col('c', 'Git for Agent Memory')}\n`);

  line(); console.log(col('b', '1. Build a shared base memory (5,000 vectors)'));
  const base = open(path.join(dir, 'base.rvf'), { dimension: DIM });
